// Add domains to IGNORE here. You may Exclude your own domain to test how Workflow behaves but eventually add your domain below so it doesnt appear in final Alerts output 
const myDomains =["yourdomain.com","testdomain.com","google.com"]; 

// value in Hrs. reduce the hours if most recent data is needed from crt.sh
const hoursAgo = 4000;  
const cutoffDate = new Date();
cutoffDate.setHours(cutoffDate.getHours() - hoursAgo);

const alerts = [];
const seenDomains = new Set();

// 2. Processing
items.forEach(item => {
  // Use name_value from the item (Split Out creates these)
  const domain = item.json.name_value || "";

  // Use entry_timestamp if available, otherwise use current date for testing
  const rawDate = item.json.entry_timestamp || new Date().toISOString();
  const certDate = new Date(rawDate);

  // Clean wildcard prefixes (*.)
  const cleanDomain = domain.replace(/^\*\./, '');

  // LOGIC CHECKS
  const isNew = certDate > cutoffDate;
  const isSuspicious = !myDomains.includes(cleanDomain);
  const isUnique = !seenDomains.has(cleanDomain);
  const isNotEmpty = cleanDomain.length > 0;

  if (isNew && isSuspicious && isUnique && isNotEmpty) {
    seenDomains.add(cleanDomain);
    alerts.push({ json: { domain: cleanDomain, date: certDate } });
  }
});

