{"id": 1692, "name": "Markdown timesheet report generation", "views": 1677, "recentViews": 0, "totalViews": 1677, "createdAt": "2022-06-02T21:51:24.610Z", "description": "This tutorial demonstrates the creation of the HTML report via Markdown node. The main idea is to prepare a very long gext variable via the Function Node and then convert it to the HTML file. The resulting report can be downloaded from the workflow canvas directly or send via email as an attachment.

![markdownworkflow.png](fileId:647)", "workflow": {"nodes": [{"name": "On clicking 'execute'", "type": "n8n-nodes-base.manualTrigger", "position": [120, 560], "parameters": {}, "typeVersion": 1}, {"name": "SortElements", "type": "n8n-nodes-base.itemLists", "position": [480, 560], "parameters": {"options": {}, "operation": "sort", "sortFieldsUi": {"sortField": [{"fieldName": "UserName"}, {"fieldName": "TaskTitle"}, {"fieldName": "date"}]}}, "typeVersion": 1}, {"name": "Markdown", "type": "n8n-nodes-base.markdown", "position": [1340, 580], "parameters": {"mode": "markdownToHtml", "options": {"tables": true, "noHeaderId": true, "rawHeaderId": false, "simpleLineBreaks": true, "customizedHeaderId": false, "completeHTMLDocument": true}, "markdown": "={{$json["mdreport"]}}"}, "typeVersion": 1}, {"name": "CreateMDReport", "type": "n8n-nodes-base.function", "position": [1160, 580], "parameters": {"functionCode": "// created report header and custom table style
var md_reporthead="#Timesheet report\n";
var md_style =  (`
<style> table {border: 0.5px solid; border-spacing: 0px;}
        table th {border-bottom: 0.5px solid;}
        table thead {background: #D0E4F5;}
        table tr:nth-child(even) { background: #D8D8D8;}
</style>\n\n`);

var md_reportbody=md_style+md_reporthead;

//declare several variables that are used for report generation
var tablehead = "| Date | Hours | Task Description |\n|:---|:---:|---|\n";

var cur_user="";
var cur_usernum=0;

var cur_task="";
var cur_tasktotal=0;


for (item of items) {

  // Check if new user
  if (item.json.UserName != cur_user) {
    // Close previous user's task
    md_reportbody += (cur_tasktotal) ? "\n*"+cur_tasktotal.toFixed(2)+" - Total hours for this task*\n" : "";
    cur_tasktotal = 0; cur_task="";

    // add new user and embed avatar as base64 image
    cur_user = item.json.UserName;
    md_reportbody += `\n##![img](data:image/png;base64,${items[cur_usernum].binary.data.data}) ${cur_user}\n`;
    cur_usernum   += 1;
  } // Check for new user - ENDIF


  // Check if new task
  if (item.json.TaskTitle != cur_task) {

    // if not empty task - add total amount of hours for *previous* task
    md_reportbody += (cur_tasktotal) ? `\n*${cur_tasktotal.toFixed(2)} - Total hours for this task*\n` : "";

    // Add new task header and reset total hours counter
    cur_task = item.json.TaskTitle;
    md_reportbody += `\n###${cur_task}\n${tablehead}`;
    cur_tasktotal = 0;
  } // Check for new task - ENDIF

  // Add current task + update total hours
   md_reportbody += `| ${item.json.date.split('T',1)} | ${item.json.hours.toFixed(2)} | ${item.json.note} |\n`;
   cur_tasktotal += item.json.hours;
}

// Let's not forget the last task's total hours:
md_reportbody += (cur_tasktotal) ? `\n*${cur_tasktotal.toFixed(2)} - Total hours for this task*\n` : "";

// Finalise the report
md_reportbody += `\n*Timesheet report generated on: ${$now.toISODate()}*`;
md_reporthead += "\n";

return [{mdreport: md_reportbody}];"}, "typeVersion": 1}, {"name": "Send Email", "type": "n8n-nodes-base.emailSend", "disabled": true, "position": [1760, 580], "parameters": {"options": {"allowUnauthorizedCerts": false}, "subject": "TimeSheet report", "attachments": "data"}, "credentials": {"smtp": {"id": "2", "name": "info@stats.consult"}}, "typeVersion": 1}, {"name": "GetImg", "type": "n8n-nodes-base.itemLists", "position": [640, 760], "parameters": {"compare": "selectedFields", "options": {"removeOtherFields": true}, "operation": "removeDuplicates", "fieldsToCompare": {"fields": [{"fieldName": "UserAvatar"}]}}, "typeVersion": 1}, {"name": "ImgBinary", "type": "n8n-nodes-base.httpRequest", "position": [820, 760], "parameters": {"url": "={{$json["UserAvatar"]}}", "options": {}, "responseFormat": "file"}, "typeVersion": 2}, {"name": "Merge2", "type": "n8n-nodes-base.merge", "position": [980, 580], "parameters": {"join": "outer", "mode": "mergeByIndex"}, "typeVersion": 1}, {"name": "Move Binary Data1", "type": "n8n-nodes-base.moveBinaryData", "position": [1520, 580], "parameters": {"mode": "jsonToBinary", "options": {"fileName": "report.html", "mimeType": "text/html", "useRawData": true}, "convertAllData": false}, "typeVersion": 1}, {"name": "GetTimesheetRecords", "type": "n8n-nodes-base.function", "position": [300, 560], "parameters": {"functionCode": "return [{UserName: "User 1 - Lead Programmer",
